	@Test
	void stalenessDoesNotTriggerFromAgeAlone() throws Exception {
		SketchBasedJoinEstimator.Config cfg = SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withChurnSampleMin(0)
				.withChurnSamplePercent(0.0)
				.withChurnSampleMax(0);

		SketchBasedJoinEstimator est = new SketchBasedJoinEstimator(store, cfg);

		// Load one statement and publish snapshot (no churn events after rebuild)
		store.addAll(List.of(st(s1, p1, o1)));
		rebuild(est);

		// Wait so age grows; old age-based staleness would fire here
		Thread.sleep(5);

		// No churn observed, so estimator should not be considered stale
		assertFalse(est.isStale(0.01));
	}

	@Test
	void estimateCountInvalidatesPatternCacheAfterSketchMutation() throws Exception {
		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store,
				SketchBasedJoinEstimator.Config.defaults()
						.withNominalEntries(64)
						.withThrottleEveryN(1)
						.withThrottleMillis(0));

		store.add(st(s1, p1, o1));
		rebuild(estimator);

		double initial = estimator.estimateCount(SketchBasedJoinEstimator.Component.S, null, p1.stringValue(), null,
				null);
		double repeated = estimator.estimateCount(SketchBasedJoinEstimator.Component.S, null, p1.stringValue(), null,
				null);
		assertEquals(initial, repeated, 0.0d, "Expected repeated estimate reads to stay stable before mutations");

		Resource s2 = VF.createIRI("urn:s2");
		Value o2 = VF.createIRI("urn:o2");
		store.add(st(s2, p1, o2));
		estimator.addStatement(st(s2, p1, o2));

		double refreshed = estimator.estimateCount(SketchBasedJoinEstimator.Component.S, null, p1.stringValue(), null,
				null);
		assertEquals(2.0d, refreshed, 0.0d, "Expected estimate cache to invalidate immediately after sketch mutation");
	}

